define('DB_HOST', 'localhost'); define('DB_USER', 'edu'); define('DB_PASS', ''); define('DB_NAME', 'edu'); function getDB(): mysqli { static $conn = null; if ($conn === null) { $conn = new mysqli(DB_HOST, DB_USER, DB_PASS, DB_NAME); if ($conn->connect_error) { http_response_code(500); die(json_encode(['error' => 'Database connection failed: ' . $conn->connect_error])); } $conn->set_charset('utf8mb4'); } return $conn; } function initSession(): void { if (session_status() === PHP_SESSION_NONE) { session_name('edu_admin'); session_start(); } } function setCorsHeaders(): void { $origin = $_SERVER['HTTP_ORIGIN'] ?? '*'; header("Access-Control-Allow-Origin: $origin"); header("Access-Control-Allow-Methods: GET, POST, PUT, DELETE, OPTIONS"); header("Access-Control-Allow-Headers: Content-Type, Authorization"); header("Access-Control-Allow-Credentials: true"); header("Content-Type: application/json; charset=utf-8"); if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') { http_response_code(204); exit; } } function jsonResponse(mixed $data, int $code = 200): void { http_response_code($code); echo json_encode($data, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT); exit; } function jsonError(string $msg, int $code = 400): void { jsonResponse(['error' => $msg], $code); } function isAdmin(): bool { initSession(); return !empty($_SESSION['admin_id']); } function requireAdmin(): void { if (!isAdmin()) { jsonError('Unauthorized', 401); } } define('UPLOAD_DIR', __DIR__ . '/uploads/'); define('UPLOAD_URL', '/backend/uploads/'); define('MAX_UPLOAD_SIZE', 20 * 1024 * 1024); define('ALLOWED_IMAGE_TYPES', ['image/jpeg', 'image/png', 'image/webp', 'image/gif', 'image/svg+xml']); 
